#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Make QA auditor tolerate the startup ensure_qa_columns() lock-timeout (columns already
exist) instead of crashing (exit-0-safe, backup+py_compile+auto-restore). Then restart all
10 QA workers. Root cause: worker runs ALTER TABLE on startup; new lock_timeout=3s (correct
gridlock guard) cancels it -> worker died. Fix = wrap the call in try/except+rollback."""
import os,sys,json,time,subprocess,shutil
F="/opt/atlas/qa/atlas_qa_auditor.py"
def sh(c,t=40):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
out={"kind":"patch_qa","ts":int(time.time())}
try:
    src=open(F).read(); lines=src.split('\n')
    bak=F+".bak.%d"%int(time.time()); shutil.copy2(F,bak); out["backup"]=bak
    target=None
    for i,ln in enumerate(lines):
        if 'ensure_qa_columns(' in ln and ln.strip().startswith('ensure_qa_columns('):
            target=i; break
    if target is None:
        out["result"]="call site not found"
    else:
        ln=lines[target]; indent=ln[:len(ln)-len(ln.lstrip())]; call=ln.strip()
        repl=[indent+"try:",
              indent+"    "+call,
              indent+"except Exception:",
              indent+"    try: conn.rollback()",
              indent+"    except Exception: pass"]
        lines[target:target+1]=repl
        newsrc='\n'.join(lines)
        tmp=F+".new"; open(tmp,"w").write(newsrc)
        chk=subprocess.run(["/opt/atlas/venv/bin/python","-m","py_compile",tmp],capture_output=True,text=True)
        out["py_compile_rc"]=chk.returncode; out["py_compile_err"]=chk.stderr.strip()[:200]
        if chk.returncode==0:
            shutil.copymode(F,tmp); os.replace(tmp,F); out["result"]="PATCHED line %d"%(target+1)
        else:
            os.remove(tmp); out["result"]="REVERTED (compile failed)"
    out["patched_region"]=sh("sed -n '%d,%dp' %s"%(max(1,(target or 1)-1),(target or 1)+6,F)) if target is not None else ""
    # restart all QA workers
    sh("systemctl reset-failed 'atlas-qa-auditor@*' 2>/dev/null")
    out["restart"]=sh("systemctl restart $(for i in $(seq 1 10); do echo atlas-qa-auditor@$i.service; done) 2>&1 | tail -1; echo done", t=50)
    time.sleep(10)
    out["qa_active_after"]=sh("systemctl list-units 'atlas-qa-auditor@*.service' --state=active --no-legend --plain 2>/dev/null|wc -l")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/patch-qa.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"patch_qa","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
